    45→## 2  Common Library: `sc_core`
    46→
    47→All services link against a minimal abstraction library that standardises
    48→logging, config, tracing, JSON and Protobuf helpers.
    49→
    50→```c
    51→/* File: sc_core/logger.h */
    52→#ifndef SC_CORE_LOGGER_H
    53→#define SC_CORE_LOGGER_H
    54→
    55→#include <stdio.h>
    56→#include <time.h>
    57→
    58→typedef enum {
    59→    SC_LOG_DEBUG,
    60→    SC_LOG_INFO,
    61→    SC_LOG_WARN,
    62→    SC_LOG_ERROR
    63→} sc_log_level_t;
    64→
    65→/**
    66→ * Initialise the global logger.
    67→ * @param level Minimum level that will be emitted.
    68→ * @return 0 on success, -1 on failure (errno is set).
    69→ */
    70→int sc_log_init(sc_log_level_t level);
    71→
    72→/**
    73→ * Log a formatted message. Always thread-safe.
    74→ */
    75→void sc_log(sc_log_level_t level, const char *fmt, ...);
    76→
    77→/* Convenience macros */
    78→#define SC_LOGD(...) sc_log(SC_LOG_DEBUG, __VA_ARGS__)
    79→#define SC_LOGI(...) sc_log(SC_LOG_INFO,  __VA_ARGS__)
    80→#define SC_LOGW(...) sc_log(SC_LOG_WARN,  __VA_ARGS__)
    81→#define SC_LOGE(...) sc_log(SC_LOG_ERROR, __VA_ARGS__)
    82→
    83→#endif /* SC_CORE_LOGGER_H */
    84→```
