    86→```c
    87→/* File: sc_core/logger.c */
    88→#define _POSIX_C_SOURCE 200809L
    89→#include "logger.h"
    90→#include <stdarg.h>
    91→#include <pthread.h>
    92→#include <string.h>
    93→
    94→static struct {
    95→    sc_log_level_t min_level;
    96→    pthread_mutex_t mtx;
    97→    FILE *stream;
    98→} g_ctx = { .min_level = SC_LOG_INFO, .mtx = PTHREAD_MUTEX_INITIALIZER,
    99→            .stream = NULL };
   100→
   101→static const char *level_to_str(sc_log_level_t lvl) {
   102→    switch (lvl) {
   103→        case SC_LOG_DEBUG: return "DEBUG";
   104→        case SC_LOG_INFO:  return "INFO ";
   105→        case SC_LOG_WARN:  return "WARN ";
   106→        default:           return "ERROR";
   107→    }
   108→}
   109→
   110→int sc_log_init(sc_log_level_t level) {
   111→    g_ctx.min_level = level;
   112→    g_ctx.stream = stderr;
   113→    return 0;
   114→}
   115→
   116→void sc_log(sc_log_level_t level, const char *fmt, ...) {
   117→    if (level < g_ctx.min_level) return;
   118→
   119→    time_t now = time(NULL);
   120→    struct tm tm_now;
   121→    localtime_r(&now, &tm_now);
   122→
   123→    char ts[32];
   124→    strftime(ts, sizeof ts, "%Y-%m-%dT%H:%M:%S", &tm_now);
   125→
   126→    pthread_mutex_lock(&g_ctx.mtx);
   127→    fprintf(g_ctx.stream, "%s [%s] ", ts, level_to_str(level));
   128→
   129→    va_list ap;
   130→    va_start(ap, fmt);
   131→    vfprintf(g_ctx.stream, fmt, ap);
   132→    va_end(ap);
   133→
   134→    fputc('\n', g_ctx.stream);
   135→    fflush(g_ctx.stream);
   136→    pthread_mutex_unlock(&g_ctx.mtx);
   137→}
