   142→## 3  Canonical Service Template
   143→
   144→Every new service clones this template, wires its domain logic, and registers
   145→with Consul for discovery.
   146→
   147→```c
   148→/* File: svc_template/main.c */
   149→#define _DEFAULT_SOURCE
   150→#include <microhttpd.h>
   151→#include <signal.h>
   152→#include <stdlib.h>
   153→#include "sc_core/logger.h"
   154→#include "router.h"
   155→
   156→#define PORT 8080
   157→
   158→static volatile sig_atomic_t running = 1;
   159→
   160→static void handle_sig(int sig) {
   161→    (void)sig;
   162→    running = 0;
   163→}
   164→
   165→int main(void) {
   166→    /* 1. Initialise cross-cutting concerns */
   167→    sc_log_init(SC_LOG_DEBUG);
   168→
   169→    SC_LOGI("Starting Palette Service v1.2.0");
   170→
   171→    /* 2. Configure graceful termination */
   172→    struct sigaction sa = { .sa_handler = handle_sig };
   173→    sigaction(SIGINT, &sa, NULL);
   174→    sigaction(SIGTERM, &sa, NULL);
   175→
   176→    /* 3. Start HTTP daemon */
   177→    struct MHD_Daemon *daemon = MHD_start_daemon(
   178→        MHD_USE_SELECT_INTERNALLY | MHD_USE_EPOLL_INTERNALLY,
   179→        PORT, NULL, NULL, &router_dispatch, NULL,
   180→        MHD_OPTION_CONNECTION_TIMEOUT,  (unsigned int)10,
   181→        MHD_OPTION_END);
   182→
   183→    if (!daemon) {
   184→        SC_LOGE("Failed to start HTTP daemon");
   185→        return EXIT_FAILURE;
   186→    }
   187→
   188→    /* 4. Main loop */
   189→    while (running) {
   190→        sleep(1);
   191→    }
   192→
   193→    /* 5. Shutdown */
   194→    MHD_stop_daemon(daemon);
   195→    SC_LOGI("Shutdown complete");
   196→    return EXIT_SUCCESS;
   197→}
   198→```
   199→
   200→`router_dispatch` is generated by a compile-time code-gen step that turns an
   201→OpenAPI spec (`openapi.yaml`) and a GraphQL schema (`schema.graphql`) into a
   202→multipart dispatcher.  
   203→For brevity, we hand-write a minimal implementation below.
