   260→```c
   261→/* File: palette/repository_sqlite.c */
   262→#define _GNU_SOURCE
   263→#include "repository.h"
   264→#include "sc_core/logger.h"
   265→#include <sqlite3.h>
   266→#include <errno.h>
   267→
   268→static sqlite3 *db = NULL;
   269→
   270→static int ensure_db(void) {
   271→    if (db) return 0;
   272→    int rc = sqlite3_open("data/palette.db", &db);
   273→    if (rc != SQLITE_OK) {
   274→        SC_LOGE("SQLite open error: %s", sqlite3_errmsg(db));
   275→        return -EIO;
   276→    }
   277→    char *err = NULL;
   278→    const char *ddl =
   279→        "CREATE TABLE IF NOT EXISTS palette ("
   280→        "id INTEGER PRIMARY KEY,"
   281→        "name TEXT NOT NULL,"
   282→        "r INTEGER NOT NULL,"
   283→        "g INTEGER NOT NULL,"
   284→        "b INTEGER NOT NULL,"
   285→        "a INTEGER NOT NULL);";
   286→    rc = sqlite3_exec(db, ddl, NULL, NULL, &err);
   287→    if (rc != SQLITE_OK) {
   288→        SC_LOGE("SQLite DDL error: %s", err);
   289→        sqlite3_free(err);
   290→        return -EIO;
   291→    }
   292→    return 0;
   293→}
   294→
   295→int palette_repo_save(const palette_t *p) {
   296→    if (!p) return -EINVAL;
   297→    if (ensure_db() < 0) return -EIO;
   298→
   299→    const char *sql =
   300→        "INSERT INTO palette(id, name, r, g, b, a) "
   301→        "VALUES(?1, ?2, ?3, ?4, ?5, ?6) "
   302→        "ON CONFLICT(id) DO UPDATE SET "
   303→        "name=excluded.name, r=excluded.r, g=excluded.g, "
   304→        "b=excluded.b, a=excluded.a;";
   305→
   306→    sqlite3_stmt *stmt = NULL;
   307→    if (sqlite3_prepare_v2(db, sql, -1, &stmt, NULL) != SQLITE_OK) {
   308→        SC_LOGE("SQLite prepare error: %s", sqlite3_errmsg(db));
   309→        return -EIO;
   310→    }
   311→
   312→    sqlite3_bind_int   (stmt, 1, p->id);
   313→    sqlite3_bind_text  (stmt, 2, p->name, -1, SQLITE_TRANSIENT);
   314→    sqlite3_bind_int   (stmt, 3, p->r);
   315→    sqlite3_bind_int   (stmt, 4, p->g);
   316→    sqlite3_bind_int   (stmt, 5, p->b);
   317→    sqlite3_bind_int   (stmt, 6, p->a);
   318→
   319→    int rc = sqlite3_step(stmt);
   320→    sqlite3_finalize(stmt);
   321→    return (rc == SQLITE_DONE) ? 0 : -EIO;
   322→}
   323→
   324→int palette_repo_get(uint32_t id, palette_t *out) {
   325→    if (!out) return -EINVAL;
   326→    if (ensure_db() < 0) return -EIO;
   327→
   328→    const char *sql = "SELECT id, name, r, g, b, a FROM palette WHERE id=?1;";
   329→    sqlite3_stmt *stmt = NULL;
   330→    if (sqlite3_prepare_v2(db, sql, -1, &stmt, NULL) != SQLITE_OK) {
   331→        SC_LOGE("SQLite prepare error: %s", sqlite3_errmsg(db));
   332→        return -EIO;
   333→    }
   334→    sqlite3_bind_int(stmt, 1, id);
   335→
   336→    int rc = sqlite3_step(stmt);
   337→    if (rc == SQLITE_ROW) {
   338→        out->id   = sqlite3_column_int(stmt, 0);
   339→        strncpy(out->name, (const char *)sqlite3_column_text(stmt, 1), sizeof out->name);
   340→        out->r    = sqlite3_column_int(stmt, 2);
   341→        out->g    = sqlite3_column_int(stmt, 3);
   342→        out->b    = sqlite3_column_int(stmt, 4);
   343→        out->a    = sqlite3_column_int(stmt, 5);
   344→        sqlite3_finalize(stmt);
   345→        return 0;
   346→    }
   347→    sqlite3_finalize(stmt);
   348→    return -ENOENT;
   349→}
   350→
   351→ssize_t palette_repo_list(size_t offset, size_t limit, palette_t *out) {
   352→    if (!out || !limit) return -EINVAL;
   353→    if (ensure_db() < 0) return -EIO;
   354→
   355→    const char *sql =
   356→        "SELECT id, name, r, g, b, a FROM palette "
   357→        "ORDER BY id LIMIT ?1 OFFSET ?2;";
   358→    sqlite3_stmt *stmt = NULL;
   359→    if (sqlite3_prepare_v2(db, sql, -1, &stmt, NULL) != SQLITE_OK) {
   360→        SC_LOGE("SQLite prepare error: %s", sqlite3_errmsg(db));
   361→        return -EIO;
   362→    }
   363→    sqlite3_bind_int(stmt, 1, limit);
   364→    sqlite3_bind_int(stmt, 2, offset);
   365→
   366→    ssize_t count = 0;
   367→    while (sqlite3_step(stmt) == SQLITE_ROW && count < (ssize_t)limit) {
   368→        palette_t *p = &out[count++];
   369→        p->id = sqlite3_column_int(stmt, 0);
   370→        strncpy(p->name, (const char *)sqlite3_column_text(stmt, 1), sizeof p->name);
   371→        p->r = sqlite3_column_int(stmt, 2);
   372→        p->g = sqlite3_column_int(stmt, 3);
   373→        p->b = sqlite3_column_int(stmt, 4);
   374→        p->a = sqlite3_column_int(stmt, 5);
   375→    }
   376→    sqlite3_finalize(stmt);
   377→    return count;
   378→}
