   381→### 4.3  REST + GraphQL Router
   382→
   383→```c
   384→/* File: svc_template/router.c */
   385→#include <microhttpd.h>
   386→#include "sc_core/logger.h"
   387→#include "palette/repository.h"
   388→#include <cjson/cJSON.h>
   389→#include <string.h>
   390→
   391→static int json_response(struct MHD_Connection *conn,
   392→                         const cJSON *json, int status) {
   393→    char *payload = cJSON_PrintUnformatted(json);
   394→    struct MHD_Response *resp =
   395→        MHD_create_response_from_buffer(strlen(payload), payload,
   396→                                        MHD_RESPMEM_MUST_FREE);
   397→    if (!resp) return MHD_NO;
   398→
   399→    MHD_add_response_header(resp, "Content-Type", "application/json");
   400→    int ret = MHD_queue_response(conn, status, resp);
   401→    MHD_destroy_response(resp);
   402→    return ret;
   403→}
   404→
   405→static int handle_get_palette(struct MHD_Connection *conn,
   406→                              uint32_t id) {
   407→    palette_t p;
   408→    if (palette_repo_get(id, &p) != 0) {
   409→        cJSON *err = cJSON_CreateObject();
   410→        cJSON_AddStringToObject(err, "error", "Palette not found");
   411→        return json_response(conn, err, MHD_HTTP_NOT_FOUND);
   412→    }
   413→
   414→    cJSON *json = cJSON_CreateObject();
   415→    cJSON_AddNumberToObject(json, "id",   p.id);
   416→    cJSON_AddStringToObject(json, "name", p.name);
   417→    cJSON_AddNumberToObject(json, "r",    p.r);
   418→    cJSON_AddNumberToObject(json, "g",    p.g);
   419→    cJSON_AddNumberToObject(json, "b",    p.b);
   420→    cJSON_AddNumberToObject(json, "a",    p.a);
   421→    return json_response(conn, json, MHD_HTTP_OK);
   422→}
   423→
   424→int router_dispatch(void *cls,
   425→                    struct MHD_Connection *connection,
   426→                    const char *url, const char *method,
   427→                    const char *ver, const char *upload_data,
   428→                    size_t *upload_data_size, void **con_cls) {
   429→    (void)cls; (void)ver; (void)upload_data; (void)upload_data_size; (void)con_cls;
   430→
   431→    SC_LOGD("Incoming %s %s", method, url);
   432→
   433→    /* Example route: GET /v1/palette/<id> */
   434→    if (strcmp(method, "GET") == 0 &&
   435→        strncmp(url, "/v1/palette/", 12) == 0) {
   436→
   437→        uint32_t id = (uint32_t)strtoul(url + 12, NULL, 10);
   438→        return handle_get_palette(connection, id);
   439→    }
   440→
   441→    /* Default 404 */
   442→    cJSON *err = cJSON_CreateObject();
   443→    cJSON_AddStringToObject(err, "error", "Route not found");
   444→    return json_response(connection, err, MHD_HTTP_NOT_FOUND);
   445→}
   446→```
