   450→## 5  GraphQL Gateway Stub
   451→
   452→The gateway composes service schemas using Apollo Federation syntax
   453→and delegates sub-queries through the internal gRPC mesh.  
   454→Below is a trimmed skeleton that wraps our Palette service.
   455→
   456→```c
   457→/* File: gateway/resolvers/palette_resolver.c */
   458→#include "sc_core/logger.h"
   459→#include <grpc/grpc.h>
   460→#include <grpc/byte_buffer.h>
   461→#include "generated/palette.grpc.pb-c.h"
   462→
   463→bool gql_resolve_palette(struct gql_query_ctx *ctx) {
   464→    uint32_t id = gql_arg_u32(ctx, "id");
   465→    Palette__GetRequest req = PALETTE__GET_REQUEST__INIT;
   466→    req.id = id;
   467→
   468→    /* Send over gRPC */
   469→    grpc_channel *ch = grpc_insecure_channel_create("palette:50051", NULL, NULL);
   470→    grpc_call *call = grpc_channel_create_call(
   471→        ch, NULL, GRPC_PROPAGATE_DEFAULT, ctx->cq,
   472→        grpc_slice_from_static_string("/palette.Palette/Get"),
   473→        NULL, gpr_inf_future(GPR_CLOCK_REALTIME), NULL);
   474→
   475→    grpc_metadata_array md_arr;
   476→    grpc_metadata_array_init(&md_arr);
   477→
   478→    grpc_byte_buffer *payload =
   479→        grpc_raw_byte_buffer_create(NULL, 0);
   480→
   481→    grpc_op ops[6];
   482→    memset(ops, 0, sizeof ops);
   483→    ops[0].op = GRPC_OP_SEND_INITIAL_METADATA;
   484→    ops[0].data.send_initial_metadata.count = 0;
   485→
   486→    ops[1].op = GRPC_OP_SEND_MESSAGE;
   487→    ops[1].data.send_message.send_message = payload;
   488→
   489→    ops[2].op = GRPC_OP_SEND_CLOSE_FROM_CLIENT;
   490→
   491→    ops[3].op = GRPC_OP_RECV_INITIAL_METADATA;
   492→    ops[3].data.recv_initial_metadata.recv_initial_metadata = &md_arr;
   493→
   494→    grpc_status_code status;
   495→    grpc_slice details;
   496→    ops[4].op = GRPC_OP_RECV_STATUS_ON_CLIENT;
   497→    ops[4].data.recv_status_on_client.status = &status;
   498→    ops[4].data.recv_status_on_client.status_details = &details;
   499→
   500→    grpc_call_error cerr = grpc_call_start_batch(call, ops, 5, NULL, NULL);
   501→    if (cerr != GRPC_CALL_OK) {
   502→        SC_LOGE("gRPC start batch failed");
   503→        return false;
   504→    }
   505→
   506→    grpc_completion_queue_pluck(ctx->cq, NULL, gpr_inf_future(GPR_CLOCK_REALTIME), NULL);
   507→
   508→    /* Transform Protobuf to GraphQL JSON */
   509→    if (status != GRPC_STATUS_OK) {
   510→        gql_error(ctx, "Palette service error");
   511→        return false;
   512→    }
   513→
   514→    /* Omitted: decode response into ctx->response */
   515→
   516→    grpc_metadata_array_destroy(&md_arr);
   517→    grpc_byte_buffer_destroy(payload);
   518→    grpc_call_destroy(call);
   519→    grpc_channel_destroy(ch);
   520→    return true;
   521→}
   522→```
