    41→
    42→#define DEFAULT_PORT                8080
    43→#define DEFAULT_MAX_TEXTURE_SIZE    4096   /* pixels in either dimension */
    44→#define DEFAULT_SCALE               8.0f
    45→#define MAX_LOG_LINE                1024
    46→#define CONFIG_ENV_VAR              "SC_TEXTURE_CONFIG"
    47→
    48→/* ---------- Logging ------------------------------------------------------ */
    49→
    50→typedef enum {
    51→    LOG_DEBUG = 0,
    52→    LOG_INFO,
    53→    LOG_WARN,
    54→    LOG_ERROR,
    55→    LOG_FATAL
    56→} LogLevel;
    57→
    58→static const char *LOG_LEVEL_NAMES[] = {
    59→    "DEBUG", "INFO", "WARN", "ERROR", "FATAL"
    60→};
    61→
    62→static LogLevel g_log_level = LOG_INFO;
    63→
    64→/* Variadic logger */
    65→static void log_msg(LogLevel level, const char *fmt, ...)
    66→{
    67→    if (level < g_log_level)
    68→        return;
    69→
    70→    char tsbuf[32];
    71→    time_t  now  = time(NULL);
    72→    struct tm tm = *localtime(&now);
    73→    strftime(tsbuf, sizeof(tsbuf), "%Y-%m-%d %H:%M:%S", &tm);
    74→
    75→    fprintf(level >= LOG_ERROR ? stderr : stdout,
    76→            "%s [%s] ", tsbuf, LOG_LEVEL_NAMES[level]);
    77→
    78→    va_list ap;
    79→    va_start(ap, fmt);
    80→    vfprintf(level >= LOG_ERROR ? stderr : stdout, fmt, ap);
    81→    va_end(ap);
    82→    fputc('\n', level >= LOG_ERROR ? stderr : stdout);
    83→
    84→    if (level == LOG_FATAL)
    85→        exit(EXIT_FAILURE);
    86→}
    87→
    88→/* ---------- Configuration ------------------------------------------------ */
    89→
    90→typedef struct {
    91→    unsigned short port;
    92→    unsigned       max_texture_size; /* maximum width/height */
    93→    LogLevel       log_level;
    94→} ServiceConfig;
    95→
    96→/* Forward-decl for default config generator */
    97→static void config_set_defaults(ServiceConfig *cfg);
    98→
    99→/* Reads configuration from a JSON file. Unknown keys are ignored. */
   100→static int config_from_file(const char *path, ServiceConfig *cfg)
   101→{
   102→    FILE *fp = fopen(path, "r");
   103→    if (!fp)
   104→        return -1;
   105→
   106→    fseek(fp, 0, SEEK_END);
   107→    long len = ftell(fp);
   108→    rewind(fp);
   109→
   110→    char *text = malloc(len + 1);
   111→    if (!text) { fclose(fp); return -1; }
   112→    fread(text, 1, len, fp);
   113→    text[len] = '\0';
   114→    fclose(fp);
   115→
   116→    cJSON *json = cJSON_Parse(text);
   117→    free(text);
   118→
   119→    if (!json) {
   120→        log_msg(LOG_ERROR, "Config parse error at pos %zu", cJSON_GetErrorPtr() - text);
   121→        return -1;
   122→    }
   123→
   124→    cJSON *val;
   125→    if ((val = cJSON_GetObjectItem(json, "port")) && cJSON_IsNumber(val))
   126→        cfg->port = (unsigned short)val->valueint;
   127→
   128→    if ((val = cJSON_GetObjectItem(json, "max_texture_size")) && cJSON_IsNumber(val))
   129→        cfg->max_texture_size = (unsigned)val->valueint;
   130→
   131→    if ((val = cJSON_GetObjectItem(json, "log_level")) && cJSON_IsString(val)) {
   132→        const char *lvl = cJSON_GetStringValue(val);
   133→        for (size_t i = 0; i < sizeof(LOG_LEVEL_NAMES)/sizeof(LOG_LEVEL_NAMES[0]); ++i) {
   134→            if (strcasecmp(lvl, LOG_LEVEL_NAMES[i]) == 0) {
   135→                cfg->log_level = (LogLevel)i;
   136→                break;
   137→            }
   138→        }
   139→    }
   140→
   141→    cJSON_Delete(json);
   142→    return 0;
   143→}
   144→
   145→static void config_set_defaults(ServiceConfig *cfg)
   146→{
   147→    cfg->port             = DEFAULT_PORT;
   148→    cfg->max_texture_size = DEFAULT_MAX_TEXTURE_SIZE;
   149→    cfg->log_level        = LOG_INFO;
   150→}
