   152→/* ---------- Value-Noise Generator --------------------------------------- */
   153→
   154→/* Simple hash-based 2D value noise (deterministic) */
   155→static inline float hash2i(int x, int y)
   156→{
   157→    /* Jenkins hash variant */
   158→    unsigned int h = (unsigned int)(x * 374761393u + y * 668265263u); /* large primes */
   159→    h = (h ^ (h >> 13u)) * 1274126177u;
   160→    return (float)(h & 0xFFFF) / 65535.0f;
   161→}
   162→
   163→static inline float lerp(float a, float b, float t) { return a + t*(b-a); }
   164→
   165→/* Bilinear interpolation of hashed corner values */
   166→static float value_noise(float x, float y)
   167→{
   168→    int xi = (int)floorf(x);
   169→    int yi = (int)floorf(y);
   170→
   171→    float xf = x - xi;
   172→    float yf = y - yi;
   173→
   174→    float v00 = hash2i(xi,     yi);
   175→    float v10 = hash2i(xi + 1, yi);
   176→    float v01 = hash2i(xi,     yi + 1);
   177→    float v11 = hash2i(xi + 1, yi + 1);
   178→
   179→    float i1 = lerp(v00, v10, xf);
   180→    float i2 = lerp(v01, v11, xf);
   181→
   182→    return lerp(i1, i2, yf);
   183→}
   184→
   185→/* Fractal Brownian Motion wrapper for richer texture */
   186→static float fbm(float x, float y, int octaves, float lacunarity, float gain)
   187→{
   188→    float total = 0.0f;
   189→    float amp   = 1.0f;
   190→    for (int i = 0; i < octaves; ++i) {
   191→        total += value_noise(x, y) * amp;
   192→        x      *= lacunarity;
   193→        y      *= lacunarity;
   194→        amp    *= gain;
   195→    }
   196→    return total;
   197→}
   198→
   199→/* Generates a binary PGM buffer (always 8-bit grayscale). */
   200→static int generate_texture_pgm(unsigned width,
   201→                                unsigned height,
   202→                                float     scale,
   203→                                unsigned char **out_buf,
   204→                                size_t    *out_size)
   205→{
   206→    if (!out_buf || !out_size)
   207→        return -1;
   208→
   209→    const size_t header_len = 32;
   210→    const size_t img_len    = width * height;
   211→    size_t total_len        = header_len + img_len;
   212→
   213→    unsigned char *buf = malloc(total_len);
   214→    if (!buf)
   215→        return -1;
   216→
   217→    int header_written = snprintf((char*)buf, header_len, "P5\n%u %u\n255\n", width, height);
   218→    if (header_written < 0 || (size_t)header_written >= header_len) {
   219→        free(buf);
   220→        return -1;
   221→    }
   222→
   223→    unsigned char *pixels = buf + header_written;
   224→    float inv_scale       = 1.0f / (scale <= 0.0f ? DEFAULT_SCALE : scale);
   225→
   226→    for (unsigned y = 0; y < height; ++y) {
   227→        for (unsigned x = 0; x < width; ++x) {
   228→            float nx = x * inv_scale;
   229→            float ny = y * inv_scale;
   230→            float v  = fbm(nx, ny, 5, 2.0f, 0.5f); /* 5 octave FBM */
   231→            /* Normalize */
   232→            v = fminf(fmaxf(v, 0.0f), 1.0f);
   233→            pixels[y*width + x] = (unsigned char)(v * 255.0f);
   234→        }
   235→    }
   236→
   237→    *out_buf  = buf;
   238→    *out_size = header_written + img_len;
   239→    return 0;
   240→}
