   242→/* ---------- HTTP Request Handling --------------------------------------- */
   243→
   244→typedef struct {
   245→    struct MHD_Daemon *daemon;
   246→    ServiceConfig      cfg;
   247→} ServiceCtx;
   248→
   249→static enum MHD_Result
   250→send_response(struct MHD_Connection *conn,
   251→              const char           *mime,
   252→              const unsigned char  *data,
   253→              size_t                size,
   254→              unsigned int          status)
   255→{
   256→    struct MHD_Response *resp = MHD_create_response_from_buffer(size,
   257→                                            (void*)data,
   258→                                            MHD_RESPMEM_MUST_COPY);
   259→    if (!resp)
   260→        return MHD_NO;
   261→
   262→    MHD_add_response_header(resp, "Content-Type", mime);
   263→    enum MHD_Result ret = MHD_queue_response(conn, status, resp);
   264→    MHD_destroy_response(resp);
   265→    return ret;
   266→}
   267→
   268→/* Helpers to parse int params safely */
   269→static int query_param_int(struct MHD_Connection *conn,
   270→                           const char *key,
   271→                           int def,
   272→                           int *out_val)
   273→{
   274→    const char *str = MHD_lookup_connection_value(conn, MHD_GET_ARGUMENT_KIND, key);
   275→    if (!str) {
   276→        *out_val = def;
   277→        return 0;
   278→    }
   279→
   280→    char *endptr = NULL;
   281→    long val = strtol(str, &endptr, 10);
   282→    if (endptr == str || val < 0 || val > INT_MAX)
   283→        return -1;
   284→
   285→    *out_val = (int)val;
   286→    return 0;
   287→}
   288→
   289→static int handle_healthz(struct MHD_Connection *conn)
   290→{
   291→    const char *ok = "{\"status\":\"ok\"}";
   292→    return send_response(conn, "application/json", (const unsigned char*)ok,
   293→                         strlen(ok), MHD_HTTP_OK);
   294→}
   295→
   296→static int handle_noise(ServiceCtx          *svc,
   297→                        struct MHD_Connection *conn)
   298→{
   299→    int width, height;
   300→    if (query_param_int(conn, "width", 256, &width)   ||
   301→        query_param_int(conn, "height", 256, &height))
   302→    {
   303→        const char *err = "{\"error\":\"invalid width/height\"}";
   304→        return send_response(conn, "application/json",
   305→                             (const unsigned char*)err,
   306→                             strlen(err),
   307→                             MHD_HTTP_BAD_REQUEST);
   308→    }
   309→
   310→    if (width  <= 0 || width  > (int)svc->cfg.max_texture_size ||
   311→        height <= 0 || height > (int)svc->cfg.max_texture_size)
   312→    {
   313→        const char *err = "{\"error\":\"dimensions out of range\"}";
   314→        return send_response(conn, "application/json",
   315→                             (const unsigned char*)err,
   316→                             strlen(err),
   317→                             MHD_HTTP_BAD_REQUEST);
   318→    }
   319→
   320→    float scale = DEFAULT_SCALE;
   321→    const char *scale_str = MHD_lookup_connection_value(conn,
   322→                                MHD_GET_ARGUMENT_KIND, "scale");
   323→    if (scale_str)
   324→        scale = strtof(scale_str, NULL);
   325→
   326→    unsigned char *buf  = NULL;
   327→    size_t         size = 0;
   328→    if (generate_texture_pgm((unsigned)width,
   329→                             (unsigned)height,
   330→                             scale,
   331→                             &buf,
   332→                             &size) != 0)
   333→    {
   334→        const char *err = "{\"error\":\"generation failed\"}";
   335→        return send_response(conn, "application/json",
   336→                             (const unsigned char*)err,
   337→                             strlen(err),
   338→                             MHD_HTTP_INTERNAL_SERVER_ERROR);
   339→    }
   340→
   341→    enum MHD_Result res = send_response(conn, "image/x-pgm", buf, size,
   342→                                        MHD_HTTP_OK);
   343→    free(buf);
   344→    return res;
   345→}
   346→
   347→/* libmicrohttpd callback */
   348→static enum MHD_Result
   349→request_router(void                *cls,
   350→               struct MHD_Connection *connection,
   351→               const char           *url,
   352→               const char           *method,
   353→               const char           *version,
   354→               const char           *upload_data,
   355→               size_t               *upload_data_size,
   356→               void                **con_cls)
   357→{
   358→    (void)cls; (void)version; (void)upload_data; (void)upload_data_size; (void)con_cls;
   359→
   360→    if (strcmp(method, "GET") != 0)
   361→        return MHD_NO;
   362→
   363→    ServiceCtx *svc = (ServiceCtx*)cls;
   364→
   365→    if (strcmp(url, "/healthz") == 0) {
   366→        return handle_healthz(connection);
   367→    }
   368→    else if (strcmp(url, "/v1/noise") == 0) {
   369→        return handle_noise(svc, connection);
   370→    }
   371→    else {
   372→        const char *err = "{\"error\":\"not found\"}";
   373→        return send_response(connection, "application/json",
   374→                             (const unsigned char*)err,
   375→                             strlen(err),
   376→                             MHD_HTTP_NOT_FOUND);
   377→    }
   378→}
   379→
   380→/* ---------- Graceful Shutdown ------------------------------------------- */
   381→
   382→static volatile sig_atomic_t g_shutdown = 0;
   383→
   384→static void on_signal(int sig)
   385→{
   386→    (void)sig;
   387→    g_shutdown = 1;
   388→}
   389→
   390→/* ---------- Main -------------------------------------------------------- */
   391→
   392→int main(void)
   393→{
   394→    ServiceCtx svc;
   395→    config_set_defaults(&svc.cfg);
   396→
   397→    /* --- Load configuration file if provided -------------------------- */
   398→    const char *cfg_path = getenv(CONFIG_ENV_VAR);
   399→    if (cfg_path && *cfg_path) {
   400→        if (config_from_file(cfg_path, &svc.cfg) != 0) {
   401→            log_msg(LOG_WARN, "Falling back to default config (%s)", strerror(errno));
   402→        }
   403→    }
   404→    g_log_level = svc.cfg.log_level;
   405→
   406→    log_msg(LOG_INFO, "Texture-Service starting on port %u", svc.cfg.port);
   407→
   408→    /* --- Setup signal handlers ---------------------------------------- */
   409→    struct sigaction sa;
   410→    memset(&sa, 0, sizeof(sa));
   411→    sa.sa_handler = on_signal;
   412→    sigaction(SIGINT,  &sa, NULL);
   413→    sigaction(SIGTERM, &sa, NULL);
   414→
   415→    /* --- Start HTTP daemon -------------------------------------------- */
   416→    svc.daemon = MHD_start_daemon(MHD_USE_AUTO | MHD_USE_INTERNAL_POLLING_THREAD,
   417→                                  svc.cfg.port,
   418→                                  NULL, NULL,
   419→                                  request_router, &svc,
   420→                                  MHD_OPTION_CONNECTION_TIMEOUT, (unsigned int)10,
   421→                                  MHD_OPTION_END);
   422→    if (!svc.daemon) {
   423→        log_msg(LOG_FATAL, "Failed to start HTTP daemon");
   424→    }
